from pathlib import Path
from datetime import datetime
root=Path.cwd()
main=root/"bot/main.py"
ui_path=root/"bot/ui.py"
if not main.exists(): raise SystemExit("Запустите файл из корня проекта рядом со start.py")
backup=root/("notice_backup_"+datetime.now().strftime("%Y%m%d_%H%M%S")); backup.mkdir()
for p in (main,ui_path):
    if p.exists(): (backup/p.name).write_bytes(p.read_bytes())
text=main.read_text("utf-8")
old="DISCLAIMER='Крипто Миньон — игровая симуляция. Все отображаемые кошельки, находки и балансы являются вымышленными. Виртуальный баланс не является реальными денежными средствами и не подлежит выводу.'"; new="DISCLAIMER='ℹ️ Продукт носит исключительно развлекательный игровой характер. Подробности — в условиях использования.'"
if old in text: text=text.replace(old,new,1)
elif new not in text: raise SystemExit("Не найдена ожидаемая строка DISCLAIMER. Возможно, файл изменён вручную.")
main.write_text(text,"utf-8")
ui_path.write_text('from __future__ import annotations\n\nfrom html import escape\nfrom typing import Iterable\n\nBRAND = "◈  КРИПТО МИНЬОН"\nDISCLAIMER_SHORT = "Продукт носит исключительно развлекательный игровой характер."\n\nSTATUS_LABELS = {\n    "pending": "🟡 Ожидает активации",\n    "active": "🟢 Активна",\n    "expired": "⚪ Истекла",\n    "blocked": "🔴 Заблокирована",\n    "revoked": "⛔ Отозвана",\n    "refunded": "↩️ Возвращена",\n}\n\n\ndef divider() -> str:\n    return "━━━━━━━━━━━━━━━━━━━━"\n\n\ndef welcome_text(first_name: str | None = None) -> str:\n    name = escape(first_name or "пользователь")\n    return (\n        f"<b>{BRAND}</b>\\n"\n        f"<code>ЛИЦЕНЗИОННЫЙ ЦЕНТР</code>\\n\\n"\n        f"Привет, <b>{name}</b>! 👋\\n"\n        "Здесь можно выбрать тариф, получить лицензию и управлять доступом к приложению.\\n\\n"\n        f"{divider()}\\n"\n        "✨ <b>Что внутри</b>\\n"\n        "• безопасная активация устройства\\n"\n        "• личный кабинет лицензий\\n"\n        "• игровой сканер и виртуальный баланс\\n"\n        "• быстрая поддержка\\n"\n        f"{divider()}\\n\\n"\n        "<i>ℹ️ Подробная информация — в разделе «Условия использования».</i>\\n\\n"\n        "<b>Выберите действие ниже</b> ↓"\n    )\n\n\ndef plans_text() -> str:\n    return (\n        f"<b>{BRAND}</b>\\n"\n        "<code>ВЫБОР ТАРИФА</code>\\n\\n"\n        "Выберите подходящий срок доступа. Перед оформлением вы увидите все параметры тарифа.\\n\\n"\n        "🔐 Безопасная активация\\n"\n        "💻 Привязка к разрешённому числу устройств\\n"\n        "⚡ Ключ доступен сразу после подтверждения"\n    )\n\n\ndef plan_card(plan) -> str:\n    duration = "Без ограничения срока" if plan.duration_days is None else f"{plan.duration_days} дней"\n    starts = "после оплаты" if plan.starts_on == "payment" else "после первой активации"\n    features = []\n    try:\n        import json\n        raw = json.loads(plan.features or "[]")\n        names = {\n            "scanner_simulation": "Игровой сканер",\n            "virtual_balance": "Виртуальный баланс",\n            "personal_account": "Личный кабинет",\n        }\n        features = [names.get(item, str(item).replace("_", " ").title()) for item in raw]\n    except (TypeError, ValueError):\n        features = []\n    feature_text = "\\n".join(f"  ✓ {escape(item)}" for item in features) or "  ✓ Основные функции приложения"\n    return (\n        f"<b>{BRAND}</b>\\n"\n        "<code>КАРТОЧКА ТАРИФА</code>\\n\\n"\n        f"💎 <b>{escape(plan.name)}</b>\\n"\n        f"{escape(plan.description)}\\n\\n"\n        f"{divider()}\\n"\n        f"⭐ <b>Стоимость:</b> {plan.price} {escape(plan.currency)}\\n"\n        f"⏳ <b>Срок:</b> {duration}\\n"\n        f"🚀 <b>Начало:</b> {starts}\\n"\n        f"💻 <b>Устройств:</b> {plan.max_devices}\\n"\n        f"{divider()}\\n\\n"\n        f"<b>Доступные возможности</b>\\n{feature_text}"\n    )\n\n\ndef licenses_text(rows: Iterable[tuple]) -> str:\n    rows = list(rows)\n    if not rows:\n        return (\n            f"<b>{BRAND}</b>\\n<code>МОИ ЛИЦЕНЗИИ</code>\\n\\n"\n            "📭 <b>Здесь пока пусто</b>\\n"\n            "После покупки ваша лицензия появится в этом разделе."\n        )\n    cards = []\n    for index, (license_obj, plan, shown_key) in enumerate(rows, 1):\n        expires = license_obj.expires_at.strftime("%d.%m.%Y") if license_obj.expires_at else "бессрочно / после активации"\n        cards.append(\n            f"<b>#{index} · {escape(plan.name)}</b>\\n"\n            f"{STATUS_LABELS.get(license_obj.status, escape(license_obj.status))}\\n"\n            f"🔑 <code>{escape(shown_key)}</code>\\n"\n            f"💻 Устройств: {license_obj.activation_count}/{license_obj.max_devices}\\n"\n            f"📅 Срок: {expires}"\n        )\n    return (\n        f"<b>{BRAND}</b>\\n<code>МОИ ЛИЦЕНЗИИ</code>\\n\\n"\n        + f"\\n\\n{divider()}\\n\\n".join(cards)\n        + ""\n    )\n\n\ndef guide_text() -> str:\n    return (\n        f"<b>{BRAND}</b>\\n<code>АКТИВАЦИЯ</code>\\n\\n"\n        "<b>Четыре простых шага</b>\\n\\n"\n        "<b>1.</b> 📥 Скачайте приложение по официальной ссылке.\\n"\n        "<b>2.</b> 🔑 Скопируйте лицензионный ключ из раздела «Мои лицензии».\\n"\n        "<b>3.</b> 🖥 Откройте приложение и вставьте ключ в окно активации.\\n"\n        "<b>4.</b> ✅ Нажмите «Активировать» и дождитесь подтверждения.\\n\\n"\n        "<blockquote>Не передавайте ключ другим людям: число устройств ограничено выбранным тарифом.</blockquote>"\n    )\n\n\ndef about_text() -> str:\n    return (\n        f"<b>{BRAND}</b>\\n<code>О ПРОЕКТЕ</code>\\n\\n"\n        "«Крипто Миньон» — развлекательная игровая симуляция с лицензируемым доступом.\\n\\n"\n        "🎮 Вымышленные игровые события\\n"\n        "📊 Виртуальная статистика и баланс\\n"\n        "🛡 Безопасная серверная активация\\n"\n        "💬 Поддержка через Telegram"\n    )\n\n\ndef terms_text() -> str:\n    return (\n        f"<b>{BRAND}</b>\\n<code>ВАЖНЫЕ УСЛОВИЯ</code>\\n\\n"\n        "Покупатель получает право использования игровой симуляции на условиях выбранного тарифа.\\n\\n"\n        "• приложение не подключается к реальным кошелькам;\\n"\n        "• приложение не подбирает настоящие seed-фразы;\\n"\n        "• приложение не переводит и не выплачивает криптовалюту;\\n"\n        "• игровой баланс нельзя вывести или обменять;\\n"\n        "• приложение не гарантирует заработок."\n    )\n',"utf-8")
print("Навязчивое предупреждение убрано из экранов бота.")
print("Резервная копия:",backup)
print("Теперь выполните: python -m pytest -q; python start.py")
